// TipTap-Schema für den Serienbrief-Editor.
//
// Custom-Nodes für die Jinja-/Platzhalter-Welt (atomar, round-trippen über data-hv-token):
//   hvPlaceholder  – inline  – {{ ... }} / {{$ ... $}}
//   hvBaustein     – inline  – {{ baustein("X") }}
//   hvJinjaInline  – inline  – {% ... %} innerhalb von Fließtext
//   hvJinjaBlock   – block   – {% ... %} als eigene Zeile zwischen Blöcken
// Tabellen-Zeilen-Loop: HvTableRow trägt das Attribut loopExpr (data-hv-loop) – die Schleife
// ist Zeilen-Metadatum, KEIN Wrapper-Node, damit prosemirror-tables intakt bleibt.
//
// Markup-Erhalt (siehe Inventar): Bold/Italic/Underline parsen die im Bestand genutzten
// Inline-Styles (font-weight/font-style/text-decoration); Superscript erhält <sup>;
// Zellen behalten ihr style (text-align).

import { Node, Extension, mergeAttributes } from "@tiptap/core";
import StarterKit from "@tiptap/starter-kit";
import Underline from "@tiptap/extension-underline";
import TextAlign from "@tiptap/extension-text-align";
import Link from "@tiptap/extension-link";
import Image from "@tiptap/extension-image";
import TextStyle from "@tiptap/extension-text-style";
import Highlight from "@tiptap/extension-highlight";
import Superscript from "@tiptap/extension-superscript";
import Subscript from "@tiptap/extension-subscript";
import Table from "@tiptap/extension-table";
import TableRow from "@tiptap/extension-table-row";
import TableHeader from "@tiptap/extension-table-header";
import TableCell from "@tiptap/extension-table-cell";

function innerOfPlaceholder(token) {
	const m = /\{\{\s*([\s\S]+?)\s*\}\}/.exec(token || "");
	let inner = m ? m[1].trim() : token || "";
	inner = inner.replace(/^\$\s*/, "").replace(/\s*\$$/, "");
	return inner;
}

function bausteinLabel(token) {
	const m = /\{\{\s*(?:baustein|textbaustein)\(\s*["']([^"']+)["']\s*\)\s*\}\}/.exec(token || "");
	return m ? m[1] : token || "";
}

function updateBausteinDom(dom, token) {
	const name = bausteinLabel(token);
	const layoutMode = !!window.__hvBausteinLayoutMode;
	const previews = window.__hvBausteinLayoutPreviews || {};
	const html = previews[name] || "";
	dom.setAttribute("data-hv-kind", "baustein");
	dom.setAttribute("data-group", "baustein");
	dom.setAttribute("data-hv-baustein-name", name);
	dom.title = "Klick: Details / Input-Pfade";
	if (layoutMode && html) {
		dom.className = "baustein-preview-node";
		dom.innerHTML =
			`<span class="baustein-preview-label">⧉ ${name}</span>` +
			`<span class="baustein-preview-body">${html}</span>`;
	} else {
		dom.className = "chip baustein-chip";
		dom.textContent = "\u29C9 " + name + " \u25BE";
	}
}

// NodeView für die (atomaren) Jinja-Knoten: Doppelklick (oder einfacher Click)
// oeffnet einen Inline-Popover zum Editieren des Ausdrucks. Der Popover wird
// von App.jsx gehostet — wir dispatchen einen CustomEvent mit token, rect und
// einem save-Callback, der dann den setNodeMarkup-Transaction-Step ausfuehrt.
// Serialisierung läuft weiter über renderHTML.
function makeJinjaNodeView(tag, className, kind) {
	return ({ node, editor, getPos }) => {
		let current = node;
		const dom = document.createElement(tag);
		dom.className = className;
		dom.setAttribute("data-hv-kind", kind);
		dom.textContent = node.attrs.token;
		// Branch-Marker (else/elif innerhalb eines if-Containers) als data-Attribut
		// spiegeln, damit CSS-Selektoren ihn ansprechen können.
		if (node.attrs.branch) dom.setAttribute("data-hv-branch", node.attrs.branch);
		dom.title = "Klick: Jinja-Ausdruck bearbeiten";
		// Cursor pointer + subtile Hover-Highlight, damit der User sieht dass
		// der Knoten klickbar ist.
		dom.style.cursor = "pointer";

		const openPopover = (e) => {
			e.preventDefault();
			e.stopPropagation();
			if (!editor.isEditable) {
				console.debug("[hv-jinja-popover] editor not editable, ignore");
				return;
			}
			const rect = dom.getBoundingClientRect();
			const pos = typeof getPos === "function" ? getPos() : null;
			if (pos == null) {
				console.debug("[hv-jinja-popover] no pos, ignore");
				return;
			}
			const save = (token) => {
				editor
					.chain()
					.focus()
					.command(({ tr }) => {
						tr.setNodeMarkup(pos, undefined, { ...current.attrs, token });
						return true;
					})
					.run();
			};
			console.debug("[hv-jinja-popover] dispatching for token", current.attrs.token);
			window.dispatchEvent(
				new CustomEvent("hv-jinja-token-popover", {
					detail: {
						token: current.attrs.token,
						rect: { left: rect.left, bottom: rect.bottom, top: rect.top },
						kind,
						save,
					},
				})
			);
		};
		// Capture-Phase: greift VOR ProseMirror's eigenen Click-Handlern, sonst
		// schluckt PM den Click bei atomic nodes (Selektion). Beides — Click und
		// Dblclick — damit der User nicht zweimal klicken muss, aber Dblclick
		// als Fallback fuer User die das gewohnt sind.
		dom.addEventListener("click", openPopover, true);
		dom.addEventListener("dblclick", openPopover, true);
		return {
			dom,
			update: (updated) => {
				if (updated.type.name !== current.type.name) return false;
				current = updated;
				dom.textContent = updated.attrs.token;
				if (updated.attrs.branch) dom.setAttribute("data-hv-branch", updated.attrs.branch);
				else dom.removeAttribute("data-hv-branch");
				return true;
			},
			ignoreMutation: () => true,
		};
	};
}

const tokenAttr = {
	default: "",
	parseHTML: (el) => el.getAttribute("data-hv-token") || el.getAttribute("data-token") || "",
	renderHTML: (attrs) => ({ "data-hv-token": attrs.token }),
};

// marks: "_" -> der Node erlaubt alle Marks (Bold/Italic/Underline/TextStyle für Schriftgröße & Farbe).
// ProseMirror rendert Marks um die NodeView-DOM, der serializeToTokens-Pfad ersetzt nur den
// Chip-Span durch den rohen Token, eine umschließende <strong>/<span style="font-size:…">-Hülle
// bleibt erhalten -> Markup landet 1:1 im PDF.
export const PlaceholderNode = Node.create({
	name: "hvPlaceholder",
	inline: true,
	group: "inline",
	atom: true,
	selectable: true,
	marks: "_",
	addAttributes() {
		return {
			token: tokenAttr,
			group: {
				default: "mieter",
				parseHTML: (el) => el.getAttribute("data-group") || "mieter",
				renderHTML: (attrs) => ({ "data-group": attrs.group }),
			},
		};
	},
	parseHTML() {
		return [
			{ tag: 'span[data-hv-kind="placeholder"]' },
			{
				tag: "span.chip[data-token]",
				getAttrs: (el) => (el.getAttribute("data-group") === "baustein" ? false : null),
			},
		];
	},
	renderHTML({ node, HTMLAttributes }) {
		return [
			"span",
			mergeAttributes(HTMLAttributes, { class: "chip", "data-hv-kind": "placeholder" }),
			innerOfPlaceholder(node.attrs.token),
		];
	},
});

export const BausteinNode = Node.create({
	name: "hvBaustein",
	inline: true,
	group: "inline",
	atom: true,
	selectable: true,
	marks: "_",
	addAttributes() {
		return { token: tokenAttr };
	},
	parseHTML() {
		return [
			{ tag: 'span[data-hv-kind="baustein"]', priority: 60 },
			{ tag: 'span.chip[data-group="baustein"][data-token]', priority: 60 },
		];
	},
	renderHTML({ node, HTMLAttributes }) {
		return [
			"span",
			mergeAttributes(HTMLAttributes, {
				class: "chip",
				"data-hv-kind": "baustein",
				"data-group": "baustein",
			}),
			`⧉ ${bausteinLabel(node.attrs.token)}`,
		];
	},
	// Doppelklick öffnet das Pfad-Mapping (Input-Pfade des Bausteins) via DOM-Event,
	// das die App abfängt. Serialisierung läuft weiter über renderHTML.
	addNodeView() {
		return ({ node }) => {
			// TipTap reuses NodeViews wenn der Node-Type gleich bleibt; bei Edits
			// kommt nur `update(updated)` mit den neuen Attrs. Der Click-Handler
			// muss daher gegen eine MUTABLE Referenz lesen, nicht gegen das
			// urspr\u00FCnglich captured `node` \u2014 sonst \u00F6ffnet sich der Popover des
			// alten Bausteins.
			let current = node;
			const dom = document.createElement("span");
			updateBausteinDom(dom, node.attrs.token);
			const onPreviewRefresh = () => updateBausteinDom(dom, current.attrs.token);
			window.addEventListener("hv-baustein-preview-refresh", onPreviewRefresh);
			dom.addEventListener("click", (e) => {
				e.preventDefault();
				e.stopPropagation();
				const name = bausteinLabel(current.attrs.token);
				if (!name) return;
				const rect = dom.getBoundingClientRect();
				window.dispatchEvent(
					new CustomEvent("hv-baustein-popover", {
						detail: { name, rect: { left: rect.left, bottom: rect.bottom, top: rect.top } },
					})
				);
			});
			return {
				dom,
				ignoreMutation: () => true,
				destroy: () => {
					window.removeEventListener("hv-baustein-preview-refresh", onPreviewRefresh);
				},
				update: (updated) => {
					if (updated.type.name !== "hvBaustein") return false;
					current = updated;
					updateBausteinDom(dom, updated.attrs.token);
					return true;
				},
			};
		};
	},
});

export const JinjaInlineNode = Node.create({
	name: "hvJinjaInline",
	inline: true,
	group: "inline",
	atom: true,
	selectable: true,
	addAttributes() {
		return { token: tokenAttr };
	},
	parseHTML() {
		return [
			{ tag: 'span[data-hv-kind="jinja-inline"]', priority: 60 },
			{ tag: "span.jinja-token[data-token]", priority: 60 },
		];
	},
	renderHTML({ node, HTMLAttributes }) {
		return [
			"span",
			mergeAttributes(HTMLAttributes, { class: "jinja-token", "data-hv-kind": "jinja-inline" }),
			node.attrs.token,
		];
	},
	addNodeView() {
		return makeJinjaNodeView("span", "jinja-token", "jinja-inline");
	},
});

export const JinjaBlockNode = Node.create({
	name: "hvJinjaBlock",
	group: "block",
	atom: true,
	selectable: true,
	addAttributes() {
		return {
			token: tokenAttr,
			// CSS-Hook für else/elif innerhalb eines if-Containers (data-hv-branch
			// wird vom Parser in tokens.js gesetzt). Wird beim Serialize nicht
			// in den Token-Output kodiert — der raw token ist autoritativ.
			branch: {
				default: null,
				parseHTML: (el) => el.getAttribute("data-hv-branch") || null,
				renderHTML: (attrs) => (attrs.branch ? { "data-hv-branch": attrs.branch } : {}),
			},
		};
	},
	parseHTML() {
		return [{ tag: 'div[data-hv-kind="jinja-block"]' }];
	},
	renderHTML({ node, HTMLAttributes }) {
		return [
			"div",
			mergeAttributes(HTMLAttributes, { class: "jinja-block", "data-hv-kind": "jinja-block" }),
			node.attrs.token,
		];
	},
	addNodeView() {
		return makeJinjaNodeView("div", "jinja-block", "jinja-block");
	},
});

// Feld-Referenz INNERHALB einer Bedingung (bare identifier, z. B. mieter.anrede — NICHT {{ }}).
// Serialisiert über data-hv-name zu seinem nackten Namen.
export const FieldNode = Node.create({
	name: "hvField",
	inline: true,
	group: "inline",
	atom: true,
	selectable: true,
	marks: "_",
	addAttributes() {
		return {
			name: {
				default: "",
				parseHTML: (el) => el.getAttribute("data-hv-name") || "",
				renderHTML: (attrs) => ({ "data-hv-name": attrs.name }),
			},
			group: {
				default: "mieter",
				parseHTML: (el) => el.getAttribute("data-group") || "mieter",
				renderHTML: (attrs) => ({ "data-group": attrs.group }),
			},
		};
	},
	parseHTML() {
		return [{ tag: 'span[data-hv-kind="field"]' }];
	},
	renderHTML({ node, HTMLAttributes }) {
		return [
			"span",
			mergeAttributes(HTMLAttributes, { class: "chip field-chip", "data-hv-kind": "field" }),
			node.attrs.name,
		];
	},
});

// Inline-editierbarer {% if %}-Block: Inhalt = Bedingungsausdruck (Text + Feld-Chips).
// Serialisiert zu {% if <ausdruck> %}. Das zugehörige {% endif %} bleibt ein eigener
// (atomarer) hvJinjaBlock; der bedingte Text steht normal dazwischen.
export const IfNode = Node.create({
	name: "hvIf",
	group: "block",
	content: "inline*",
	defining: true,
	selectable: true,
	parseHTML() {
		return [{ tag: 'div[data-hv-kind="if"]' }];
	},
	renderHTML({ HTMLAttributes }) {
		return ["div", mergeAttributes(HTMLAttributes, { class: "jinja-if-block", "data-hv-kind": "if" }), 0];
	},
});

// Container für ein komplettes {% if %} ... {% endif %}: erste Kind = hvIf (Header
// mit Bedingung), danach beliebige Block-Kinder = Body. Das endif wird beim
// Serialisieren implizit angehängt — der Container besitzt also kein endif-Kind.
// NodeView fügt einen Collapse-Toggle hinzu (UI-only, nicht persistiert).
export const IfBlockNode = Node.create({
	name: "hvIfBlock",
	group: "block",
	content: "hvIf block*",
	defining: true,
	selectable: true,
	parseHTML() {
		return [{ tag: 'div[data-hv-kind="if-block"]' }];
	},
	renderHTML({ HTMLAttributes }) {
		return [
			"div",
			mergeAttributes(HTMLAttributes, { class: "jinja-if-container", "data-hv-kind": "if-block" }),
			0,
		];
	},
	addNodeView() {
		return ({ editor, getPos }) => {
			const dom = document.createElement("div");
			dom.className = "jinja-if-container";
			dom.setAttribute("data-hv-kind", "if-block");

			// Toggle-Spalte links — komplett nicht-editierbar. Wir nehmen ALLE
			// Mouse-Events VOR ProseMirror (capture-phase) ab, damit PM nicht
			// in seinen Selection-Handler springt und den Click verschluckt.
			const gutter = document.createElement("div");
			gutter.className = "jinja-if-gutter";
			gutter.setAttribute("contenteditable", "false");

			const toggle = document.createElement("button");
			toggle.type = "button";
			toggle.className = "jinja-if-toggle";
			toggle.title = "Block aus-/einklappen";
			toggle.setAttribute("aria-label", "Block aus-/einklappen");
			toggle.textContent = "▾";

			const doToggle = (e) => {
				e.preventDefault();
				e.stopPropagation();
				const collapsed = dom.classList.toggle("is-collapsed");
				toggle.textContent = collapsed ? "▸" : "▾";
				toggle.title = collapsed ? "Block ausklappen" : "Block einklappen";
			};
			// Capture-Phase + mehrere Events: PM hängt seine Handler an
			// mousedown/mouseup; wir wollen den Click trotzdem behandeln.
			toggle.addEventListener("mousedown", (e) => {
				e.preventDefault();
				e.stopPropagation();
			}, true);
			toggle.addEventListener("mouseup", (e) => {
				e.preventDefault();
				e.stopPropagation();
			}, true);
			toggle.addEventListener("click", doToggle, true);

			// Loeschen-Button: nur im Hover sichtbar (CSS). Entfernt den
			// kompletten If-Container inkl. Body — der User kann sonst nur per
			// Selektion + Backspace loeschen, was nicht offensichtlich ist.
			const deleteBtn = document.createElement("button");
			deleteBtn.type = "button";
			deleteBtn.className = "jinja-if-delete";
			deleteBtn.title = "Wenn-Block entfernen";
			deleteBtn.setAttribute("aria-label", "Wenn-Block entfernen");
			deleteBtn.textContent = "✕";
			const doDelete = (e) => {
				e.preventDefault();
				e.stopPropagation();
				if (!editor || typeof getPos !== "function") return;
				if (!window.confirm("Wenn-Block inkl. Inhalt entfernen?")) return;
				const pos = getPos();
				if (typeof pos !== "number") return;
				const node = editor.state.doc.nodeAt(pos);
				if (!node) return;
				editor
					.chain()
					.focus()
					.deleteRange({ from: pos, to: pos + node.nodeSize })
					.run();
			};
			deleteBtn.addEventListener("mousedown", (e) => {
				e.preventDefault();
				e.stopPropagation();
			}, true);
			deleteBtn.addEventListener("mouseup", (e) => {
				e.preventDefault();
				e.stopPropagation();
			}, true);
			deleteBtn.addEventListener("click", doDelete, true);

			gutter.appendChild(toggle);
			gutter.appendChild(deleteBtn);
			dom.appendChild(gutter);

			const content = document.createElement("div");
			content.className = "jinja-if-content";
			dom.appendChild(content);

			return {
				dom,
				contentDOM: content,
				ignoreMutation(mutation) {
					// Klassen-Wechsel am Wrapper (is-collapsed) NICHT als Content-Mutation
					// melden — sonst will ProseMirror den DOM re-rendern und unsere
					// Toggle-Klasse verschwindet.
					if (mutation.type === "attributes") return true;
					if (gutter.contains(mutation.target)) return true;
					return false;
				},
			};
		};
	},
});

// Tabellen-Zeile mit optionalem Loop-Ausdruck (Schleife als Zeilen-Attribut).
export const HvTableRow = TableRow.extend({
	addAttributes() {
		return {
			...this.parent?.(),
			loopExpr: {
				default: null,
				parseHTML: (el) => el.getAttribute("data-hv-loop"),
				renderHTML: (attrs) => (attrs.loopExpr ? { "data-hv-loop": attrs.loopExpr } : {}),
			},
		};
	},
	addCommands() {
		return {
			setRowLoopExpr:
				(expr) =>
				({ state, dispatch }) => {
					const { $from } = state.selection;
					for (let d = $from.depth; d > 0; d--) {
						const node = $from.node(d);
						if (node.type.name === this.name) {
							if (dispatch) {
								const pos = $from.before(d);
								dispatch(
									state.tr.setNodeMarkup(pos, undefined, {
										...node.attrs,
										loopExpr: expr || null,
									})
								);
							}
							return true;
						}
					}
					return false;
				},
		};
	},
});

// Zellen sollen ihr inline style (im Bestand: text-align) behalten.
const styleAttr = {
	style: {
		default: null,
		parseHTML: (el) => el.getAttribute("style"),
		renderHTML: (attrs) => (attrs.style ? { style: attrs.style } : {}),
	},
};
export const HvTableCell = TableCell.extend({
	addAttributes() {
		return { ...this.parent?.(), ...styleAttr };
	},
});
export const HvTableHeader = TableHeader.extend({
	addAttributes() {
		return { ...this.parent?.(), ...styleAttr };
	},
});

// Tabelle mit optionalem Rahmen-Flag. ``borders`` round-trippt über data-hv-borders am
// <table> (Muster wie HvTableRow.loopExpr). Steuert per CSS, ob im Editor solide Rahmen
// statt der gestrichelten Hilfslinie gezeigt UND im PDF echte Rahmen gedruckt werden
// (Default randlos — Tabellen sind meist reine Layout-Hilfen).
export const HvTable = Table.extend({
	addAttributes() {
		return {
			...this.parent?.(),
			borders: {
				default: false,
				parseHTML: (el) => el.hasAttribute("data-hv-borders"),
				renderHTML: (attrs) => (attrs.borders ? { "data-hv-borders": "1" } : {}),
			},
		};
	},
});

// TextStyle-Zusätze: Schriftgröße + Textfarbe (ersetzt @tiptap/extension-color, weil wir die
// Farbe mit !important rendern müssen). Grund: Frappes Print-Bundle hat im PDF-Render eine
// globale Regel `@media print { *,*:before,*:after { color:#000 !important } }`, die jede
// Inline-Farbe ohne !important überschreibt. Inline-!important schlägt das universelle !important.
//
// fontSize-Werte werden in **pt** ausgegeben (z.B. "11pt") — passt 1:1 zum PDF-Render
// (Print-CSS = 11pt). Bestandsdaten mit `font-size: 15px` bleiben dank generischem
// `el.style.fontSize`-Parser unverändert lesbar; nur neue Eingaben sind in pt.
const TextStyleExtras = Extension.create({
	name: "hvTextStyleExtras",
	addGlobalAttributes() {
		return [
			{
				types: ["textStyle"],
				attributes: {
					fontSize: {
						default: null,
						parseHTML: (el) => {
							// Erst CSSOM versuchen (validiert + normalisiert).
							const cssValue = (el.style.fontSize || "").trim();
							if (cssValue) return cssValue;
							// CSSOM hat den Wert als invalid verworfen → rohes style-Attribut
							// nachfassen. Tritt bei Bestandsdaten ohne Einheit auf
							// (z.B. ``font-size: 15`` aus Word-Imports).
							const style = el.getAttribute("style") || "";
							const match = /(?:^|;)\s*font-size\s*:\s*([^;]+)/i.exec(style);
							const raw = (match?.[1] || "").trim();
							if (!raw) return null;
							// Pure positive Zahl ohne Einheit → "pt" anhängen.
							// Andere kaputte Werte (negative Zahlen, ``abc``, ``15%`` etc)
							// verwerfen — CSSOM hat valide Werte bereits oben abgefangen,
							// also ist alles was hier ankommt kaputter Altbestand, der
							// nicht heilbar ist.
							if (/^\d+(\.\d+)?$/.test(raw)) return `${raw}pt`;
							return null;
						},
						renderHTML: (attrs) =>
							attrs.fontSize ? { style: `font-size: ${attrs.fontSize}` } : {},
					},
					color: {
						default: null,
						parseHTML: (el) => (el.style.color ? el.style.color : null),
						renderHTML: (attrs) =>
							attrs.color ? { style: `color: ${attrs.color} !important` } : {},
					},
				},
			},
		];
	},
	addCommands() {
		return {
			setFontSize:
				(size) =>
				({ chain }) =>
					chain().setMark("textStyle", { fontSize: size }).run(),
			unsetFontSize:
				() =>
				({ chain }) =>
					chain().setMark("textStyle", { fontSize: null }).removeEmptyTextStyle().run(),
			setColor:
				(color) =>
				({ chain }) =>
					chain().setMark("textStyle", { color }).run(),
			unsetColor:
				() =>
				({ chain }) =>
					chain().setMark("textStyle", { color: null }).removeEmptyTextStyle().run(),
		};
	},
});

// Zeilenabstand auf paragraph-/heading-Ebene. Setzt `style="line-height: X"` direkt aufs
// <p>/<h*> — Inline-Style überschreibt das Print-CSS (`.serienbrief-page p { line-height: 1.35 }`)
// durch höhere Spezifität, daher kein !important nötig. Werte sind einheitenlos (Word-Konvention
// 1.0 / 1.15 / 1.35 / 1.5 / 2.0).
//
// indent: Einrück-Stufen (0..5), jede Stufe = 1cm margin-left. Wird per Tab/Shift+Tab
// gesteuert (siehe Keymap unten). Tab am Zeilenanfang → indent++; Tab in der Mitte
// einer Zeile → 8 ``&nbsp;`` einfügen (Tab-Stop-Imitation).
const INDENT_MAX = 5;
const INDENT_STEP_CM = 1;
const ParagraphExtras = Extension.create({
	name: "hvParagraphExtras",
	addGlobalAttributes() {
		return [
			{
				types: ["paragraph", "heading"],
				attributes: {
					lineHeight: {
						default: null,
						parseHTML: (el) => el.style.lineHeight || null,
						renderHTML: (attrs) =>
							attrs.lineHeight ? { style: `line-height: ${attrs.lineHeight}` } : {},
					},
					indent: {
						default: 0,
						parseHTML: (el) => {
							// Aus margin-left zurückrechnen (Step = 1cm).
							const ml = el.style.marginLeft || "";
							const m = /^(-?\d+(?:\.\d+)?)cm$/.exec(ml);
							if (!m) return 0;
							const n = Math.round(parseFloat(m[1]) / INDENT_STEP_CM);
							return Math.max(0, Math.min(INDENT_MAX, n));
						},
						renderHTML: (attrs) => {
							const n = Math.max(0, Math.min(INDENT_MAX, Number(attrs.indent) || 0));
							return n > 0 ? { style: `margin-left: ${n * INDENT_STEP_CM}cm` } : {};
						},
					},
				},
			},
		];
	},
	addCommands() {
		return {
			setLineHeight:
				(value) =>
				({ chain, editor }) => {
					const types = ["paragraph", "heading"];
					let c = chain();
					for (const t of types) {
						if (editor.can().updateAttributes(t, { lineHeight: value })) {
							c = c.updateAttributes(t, { lineHeight: value });
						}
					}
					return c.run();
				},
			indentParagraph:
				() =>
				({ state, chain, editor }) => {
					const types = ["paragraph", "heading"];
					const node = state.selection.$from.node();
					const currentName = node?.type?.name;
					if (!types.includes(currentName)) return false;
					const cur = Number(node.attrs.indent || 0);
					const next = Math.min(INDENT_MAX, cur + 1);
					if (next === cur) return false;
					return chain().updateAttributes(currentName, { indent: next }).run();
				},
			outdentParagraph:
				() =>
				({ state, chain, editor }) => {
					const types = ["paragraph", "heading"];
					const node = state.selection.$from.node();
					const currentName = node?.type?.name;
					if (!types.includes(currentName)) return false;
					const cur = Number(node.attrs.indent || 0);
					const next = Math.max(0, cur - 1);
					if (next === cur) return false;
					return chain().updateAttributes(currentName, { indent: next }).run();
				},
			unsetLineHeight:
				() =>
				({ chain, editor }) => {
					const types = ["paragraph", "heading"];
					let c = chain();
					for (const t of types) {
						if (editor.can().updateAttributes(t, { lineHeight: null })) {
							c = c.updateAttributes(t, { lineHeight: null });
						}
					}
					return c.run();
				},
		};
	},
	addKeyboardShortcuts() {
		const TAB_NBSP = "        "; // 8 nbsp = ~1 Tab-Stop
		return {
			Tab: ({ editor }) => {
				const { state } = editor;
				// Nicht greifen in Tabellen-Zellen (Tabellen-Extension navigiert dort).
				if (editor.isActive("table") || editor.isActive("tableCell") || editor.isActive("tableHeader")) {
					return false;
				}
				// Nicht greifen in Listen (StarterKit hat eigene Tab-Logik für Sub-Listen).
				if (editor.isActive("bulletList") || editor.isActive("orderedList") || editor.isActive("listItem")) {
					return false;
				}
				// Nur paragraph/heading sind Indent-fähig.
				const node = state.selection.$from.node();
				if (!["paragraph", "heading"].includes(node?.type?.name)) return false;
				// Am Zeilenanfang (parentOffset == 0): indent++ statt Tab-Whitespace.
				const atStart = state.selection.empty && state.selection.$from.parentOffset === 0;
				if (atStart) {
					return editor.commands.indentParagraph();
				}
				// Sonst: Tab-Stop-Whitespace einfügen.
				return editor.chain().insertContent(TAB_NBSP).run();
			},
			"Shift-Tab": ({ editor }) => {
				const { state } = editor;
				if (editor.isActive("table") || editor.isActive("tableCell") || editor.isActive("tableHeader")) {
					return false;
				}
				if (editor.isActive("bulletList") || editor.isActive("orderedList") || editor.isActive("listItem")) {
					return false;
				}
				const node = state.selection.$from.node();
				if (!["paragraph", "heading"].includes(node?.type?.name)) return false;
				const cur = Number(node.attrs.indent || 0);
				if (cur <= 0) return false; // kein Outdent → andere Handler greifen lassen
				return editor.commands.outdentParagraph();
			},
		};
	},
});

// Komplette Extension-Liste. onImageRequest() öffnet den Upload-Flow (vom Editor injiziert).
export function buildExtensions() {
	return [
		StarterKit.configure({
			heading: { levels: [1, 2, 3] },
		}),
		Underline,
		Superscript,
		Subscript,
		TextAlign.configure({ types: ["heading", "paragraph"] }),
		Link.configure({ openOnClick: false, autolink: false }),
		TextStyle,
		TextStyleExtras,
		ParagraphExtras,
		Highlight.configure({ multicolor: true }),
		Image.configure({ inline: false, allowBase64: false }),
		HvTable.configure({ resizable: true }),
		HvTableRow,
		HvTableHeader,
		HvTableCell,
		PlaceholderNode,
		BausteinNode,
		FieldNode,
		IfNode,
		IfBlockNode,
		JinjaInlineNode,
		JinjaBlockNode,
	];
}
